#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int SA, SB, SC; scanf("%d %d %d", &SA, &SB, &SC);
        if(SA < SB && SA < SC) printf("Draw\n");
        else if(SB < SA && SB < SC) printf("Bob\n");
        else printf("Alice\n");
    }
    return 0;
}

